+#[derive(Debug, Clone, PartialEq, Eq)]
+pub enum EdgeReferenceResolution {
+    Ok,
+    CrossWorkspaceEdge {
+        target_store_root: PathBuf,
+        target_workspace_root: PathBuf,
+    },
+    DanglingEdge,
+}
