+}
+
+impl StoreLayout {
+    fn for_kind(kind: ContentKind) -> Option<Self> {
+        match kind {
+            ContentKind::Ticket => Some(Self {
+                store_dir: ".ticket",
+                entity_dir: "tickets",
+                manifest_file: "ticket.toml",
