+        &self,
+        target_id: Uuid,
+    ) -> EdgeReferenceResolution {
+        if let Some(root) = self
+            .included_store_roots
+            .iter()
+            .find(|root| entity_exists(root, self.layout, target_id))
+        {
+            let _ = root;
+            return EdgeReferenceResolution::Ok;
+        }
+
+        if let Some(root) = self
+            .discoverable_store_roots
+            .iter()
+            .find(|root| entity_exists(root, self.layout, target_id))
