+fn resolve_uuid_prefix(
+    store: &TicketStore,
+    input: &str,
+) -> Result<Uuid, ticket_api::error::StorageError> {
+    if let Ok(uuid) = Uuid::parse_str(input) {
+        return Ok(uuid);
+    }
+
+    let prefix = input.trim();
+    if prefix.len() < 8 {
+        return Err(ticket_api::error::StorageError::Other(format!(
+            "ambiguous id prefix '{}' (need at least 8 hex chars)",
+            input
+        )));
+    }
+
+    let matches: Vec<Uuid> = store
+        .list(None, None, None)?
+        .into_iter()
+        .map(|ticket| ticket.id)
+        .filter(|id| id.to_string().starts_with(prefix))
+        .collect();
+
+    match matches.as_slice() {
+        [single] => Ok(*single),
+        [] => Err(ticket_api::error::StorageError::NotFound(
+            Uuid::nil(),
+        )),
+        _ => Err(ticket_api::error::StorageError::Other(format!(
+            "ambiguous id prefix '{}' matches {} tickets",
+            input,
+            matches.len()
+        ))),
+    }
+}
